const allItems = $input.all();

const dbData = allItems[0] ? allItems[0].json : {};
const crmData = allItems[1] ? allItems[1].json : {};
const gaData = allItems[2] ? allItems[2].json : {};

const now = new Date();
const yesterday = new Date(now.getTime() - 86400000);
const reportDate = yesterday.toISOString().split('T')[0];

const dealsArray = Array.isArray(crmData) ? crmData : [];
const wonDeals = dealsArray.filter(function(d) {
  return d.properties && d.properties.dealstage === 'closedwon';
});
const lostDeals = dealsArray.filter(function(d) {
  return d.properties && d.properties.dealstage === 'closedlost';
});
const pipelineValue = dealsArray.reduce(function(sum, d) {
  return sum + parseFloat((d.properties && d.properties.amount) ? d.properties.amount : 0);
}, 0);

const mcpPayload = {
  metadata: {
    report_date: reportDate,
    generated_at: now.toISOString(),
    sources: ['postgres_database', 'hubspot_crm', 'google_analytics']
  },
  product_metrics: {
    revenue: dbData.revenue || 0,
    new_users: dbData.new_users || 0,
    churn_rate: dbData.churn_rate || 0,
    active_sessions: dbData.active_sessions || 0
  },
  sales_pipeline: {
    deals_won: wonDeals.length,
    deals_lost: lostDeals.length,
    total_pipeline_value: pipelineValue,
    total_deals_pulled: dealsArray.length
  },
  web_analytics: {
    sessions: gaData['ga:sessions'] || 0,
    pageviews: gaData['ga:pageviews'] || 0,
    bounce_rate: gaData['ga:bounceRate'] || 0,
    goal_completions: gaData['ga:goalCompletionsAll'] || 0
  },
  report_instructions: {
    tone: 'professional and concise',
    required_sections: ['Executive Highlights', 'Areas of Concern', 'Key Trends', 'Recommendations'],
    max_words: 400
  }
};

return [{ json: mcpPayload }];

const input = $input.first().json;

let narrative = '';
if (input.content && Array.isArray(input.content)) {
  narrative = input.content.map(function(c) { return c.text || ''; }).join('');
} else if (input.text) {
  narrative = input.text;
} else if (typeof input === 'string') {
  narrative = input;
} else {
  narrative = JSON.stringify(input);
}

const now = new Date();
const yesterday = new Date(now.getTime() - 86400000);
const reportDate = yesterday.toISOString().split('T')[0];
const isFriday = now.getDay() === 5;

const preview = narrative.length > 280 ? narrative.substring(0, 280) + '...' : narrative;

return [{
  json: {
    report_date: reportDate,
    is_friday: isFriday,
    narrative: narrative,
    slack_preview: preview,
    email_subject: 'Daily Performance Report - ' + reportDate,
    generated_at: now.toISOString()
  }
}];

